@@ -0,0 +1,138 @@
+import { Injectable, Logger, NotFoundException, OnModuleInit } from '@nestjs/common';
+
+import { AlgoliaService } from '@modules/algolia/algolia.service';
+import { CacheService } from '@modules/cache/cache.service';
+import { StylesService } from '@modules/db/styles/styles.service';
+import { EnvConfigService } from '@modules/env-config/env-config.service';
+
+import { shuffleArray } from '@utils/array.util';
+import { assignRandomColorToProduct } from '@utils/random-color-picker.util';
+
+import { CURATED_ADDONS_CACHE_TTL } from '@constants/env-variables.constant';
+
+import { Namespaces } from '@interfaces/cache.interface';
+import { IRelatedProduct } from '@interfaces/related-product.interface';
+
+import { LogExecution } from '@decorators/log-execution.decorator';
+
+import { AddonsCuratedResponseDto } from '@dto/addons/addons-curated-response.dto';
+
+@Injectable()
+export class AddonsService implements OnModuleInit {
+	private readonly logger = new Logger(AddonsService.name);
+
+	private readonly curatedAddonsIds: string[] = [
+		'1490500',
+		'947400',
+		'1513400',
+		'275100',
+		'103700',
+		'1587800',
+		'349500',
+		'268500',
+		'111000',
+		'1163800',
+		'1971400',
+		'1717700',
+		'1171000',
+		'1142300',
+		'291300',
+		'817300',
+		'1565600',
+		'1120900',
+		'646800',
+		'873200',
+		'1521400',
+	];
+
+	private curatedAddonsCacheTtl: number;
+	private readonly cacheKey = 'curated-addons';
+
+	constructor(
+		private readonly algoliaService: AlgoliaService,
+		private readonly styleService: StylesService,
+		private readonly cacheService: CacheService,
+		private readonly configService: EnvConfigService,
+	) {}
+
+	onModuleInit(): void {
+		this.curatedAddonsCacheTtl = this.configService.get<number>({
+			key: CURATED_ADDONS_CACHE_TTL,
+			converter: Number,
+		});
+	}
+
+	@LogExecution({
+		paramFormatter: (params) => params,
+		responseFormatter: (response: AddonsCuratedResponseDto) => response.addons.length,
+	})
+	async getCuratedAddons(): Promise<AddonsCuratedResponseDto> {
+		try {
+			const cachedData = await this.cacheService.get<AddonsCuratedResponseDto>({
+				namespace: Namespaces.CURATED_ADDONS,
+				key: this.cacheKey,
+			});
+
+			if (cachedData) {
+				this.logger.log(`Cache hit for curated addons. Cache key: ${this.cacheKey}`);
+				return cachedData;
+			}
+
+			this.logger.log(
+				'Cache miss for curated addons, fetching from Algolia and database',
+			);
+
+			const sortedCuratedIds = shuffleArray(this.curatedAddonsIds);
+
+			const [algoliaHits, listOfActiveProducts] = await Promise.all([
+				this.algoliaService.getMultipleObjects(sortedCuratedIds),
+				this.styleService.getStylesInStockByIds({
+					styleIds: sortedCuratedIds.map((id) => Number(id)),
+				}),
+			]);
+
+			const addons = algoliaHits.reduce((acc: IRelatedProduct[], hit) => {
+				if (
+					hit.product_id &&
+					hit.default_quote_qty &&
+					hit.default_unit_prices &&
+					hit.default_unit_prices.some(
+						(unitPrices) =>
+							unitPrices.quantity === hit.default_quote_qty || unitPrices.quantity === 1,
+					) &&
+					listOfActiveProducts.some(
+						(style) => Number(style.style_id) === Number(hit.product_id),
+					)
+				) {
+					const relatedProduct = this.algoliaService.mapHitToRelatedProduct(hit, null);
+					acc.push(assignRandomColorToProduct(relatedProduct, hit.colors));
+				}
+				return acc;
+			}, []);
+
+			if (addons.length === 0) {
+				this.logger.warn('No curated addons products found in stock.');
+				throw new NotFoundException('No curated addons products found in stock');
+			}
+
+			const result = { addons };
+
+			await this.cacheService.set({
+				namespace: Namespaces.CURATED_ADDONS,
+				key: this.cacheKey,
+				value: result,
+				ttl: this.curatedAddonsCacheTtl,
+			});
+
+			return result;
+		} catch (error) {
+			if (error instanceof NotFoundException) {
+				throw error;
+			}
+
+			const err = error instanceof Error ? error : new Error(String(error));
+			this.logger.error('Error fetching curated addons.', err.message, err.stack);
+			throw err;
+		}
+	}
+}
