   244→+	];
   245→+
   246→+	private curatedAddonsCacheTtl: number;
   247→+	private readonly cacheKey = 'curated-addons';
   248→+
   249→+	constructor(
   250→+		private readonly algoliaService: AlgoliaService,
   251→+		private readonly styleService: StylesService,
   252→+		private readonly cacheService: CacheService,
   253→+		private readonly configService: EnvConfigService,
   254→+	) {}
   255→+
   256→+	onModuleInit(): void {
   257→+		this.curatedAddonsCacheTtl = this.configService.get<number>({
   258→+			key: CURATED_ADDONS_CACHE_TTL,
   259→+			converter: Number,
   260→+		});
   261→+	}
   262→+
   263→+	@LogExecution({
   264→+		paramFormatter: (params) => params,
   265→+		responseFormatter: (response: AddonsCuratedResponseDto) => response.addons.length,
   266→+	})
   267→+	async getCuratedAddons(): Promise<AddonsCuratedResponseDto> {
   268→+		try {
   269→+			const cachedData = await this.cacheService.get<AddonsCuratedResponseDto>({
   270→+				namespace: Namespaces.CURATED_ADDONS,
   271→+				key: this.cacheKey,
   272→+			});
   273→+
   274→+			if (cachedData) {
   275→+				this.logger.log(`Cache hit for curated addons. Cache key: ${this.cacheKey}`);
   276→+				return cachedData;
   277→+			}
   278→+
   279→+			this.logger.log(
   280→+				'Cache miss for curated addons, fetching from Algolia and database',
   281→+			);
   282→+
   283→+			const sortedCuratedIds = shuffleArray(this.curatedAddonsIds);
   284→+
   285→+			const [algoliaHits, listOfActiveProducts] = await Promise.all([
   286→+				this.algoliaService.getMultipleObjects(sortedCuratedIds),
   287→+				this.styleService.getStylesInStockByIds({
   288→+					styleIds: sortedCuratedIds.map((id) => Number(id)),
   289→+				}),
   290→+			]);
   291→+
   292→+			const addons = algoliaHits.reduce((acc: IRelatedProduct[], hit) => {
   293→+				if (
   294→+					hit.product_id &&
   295→+					hit.default_quote_qty &&
   296→+					hit.default_unit_prices &&
   297→+					hit.default_unit_prices.some(
   298→+						(unitPrices) =>
   299→+							unitPrices.quantity === hit.default_quote_qty || unitPrices.quantity === 1,
   300→+					) &&
   301→+					listOfActiveProducts.some(
   302→+						(style) => Number(style.style_id) === Number(hit.product_id),
   303→+					)
   304→+				) {
   305→+					const relatedProduct = this.algoliaService.mapHitToRelatedProduct(hit, null);
   306→+					acc.push(assignRandomColorToProduct(relatedProduct, hit.colors));
   307→+				}
   308→+				return acc;
   309→+			}, []);
   310→+
   311→+			if (addons.length === 0) {
   312→+				this.logger.warn('No curated addons products found in stock.');
   313→+				throw new NotFoundException('No curated addons products found in stock');
   314→+			}
   315→+
   316→+			const result = { addons };
   317→+
   318→+			await this.cacheService.set({
   319→+				namespace: Namespaces.CURATED_ADDONS,
   320→+				key: this.cacheKey,
   321→+				value: result,
   322→+				ttl: this.curatedAddonsCacheTtl,
   323→+			});
   324→+
   325→+			return result;
   326→+		} catch (error) {
   327→+			if (error instanceof NotFoundException) {
   328→+				throw error;
   329→+			}
   330→+
   331→+			const err = error instanceof Error ? error : new Error(String(error));
   332→+			this.logger.error('Error fetching curated addons.', err.message, err.stack);
   333→+			throw err;
   334→+		}
   335→+	}
   336→+}
