+import { Controller, Get, HttpStatus } from '@nestjs/common';
+import { ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';
+
+import { AddonsService } from '@modules/rest/addons/addons.service';
+import { MetricsService } from '@modules/rest/related-products/metrics.service';
+
+import { dailyTrackingKeys } from '@constants/common.constant';
+
+import { LogExecution } from '@decorators/log-execution.decorator';
+
+import { AddonsCuratedResponseDto } from '@dto/addons/addons-curated-response.dto';
+
+@ApiTags('Addons Products')
+@Controller('addons')
+export class AddonsController {
+	constructor(
+		private readonly metricsService: MetricsService,
+		private readonly addonsService: AddonsService,
+	) {}
+
+	@Get('curated')
+	@ApiOperation({ summary: 'Get cheap curated addons products' })
+	@ApiResponse({
+		status: HttpStatus.OK,
+		description: 'Returns curated addons products',
+		type: AddonsCuratedResponseDto,
+	})
+	@ApiResponse({ status: HttpStatus.NOT_FOUND, description: 'Products not found' })
+	@ApiResponse({
+		status: HttpStatus.INTERNAL_SERVER_ERROR,
+		description: 'Internal server error',
+	})
+	@LogExecution({
+		paramFormatter: (params) => params,
+		responseFormatter: (response: AddonsCuratedResponseDto) => response,
+	})
+	async getCuratedAddons(): Promise<AddonsCuratedResponseDto> {
+		await this.metricsService.incrementDailyCounter(
+			dailyTrackingKeys.CURATED_ADDONS_REQUESTS,
+		);
+		return this.addonsService.getCuratedAddons();
+	}
+}
