    13→
    14→@Injectable()
    15→export class PromotionalProductsService {
    16→	private readonly logger = new Logger(PromotionalProductsService.name);
    17→
    18→	constructor(
    19→		private readonly trendingProductsService: TrendingProductsService,
    20→		private readonly dbPromotionalProductsService: DBPromotionalProductsService,
    21→		private readonly algoliaService: AlgoliaService,
