    24→
    25→	async getPromotionalProducts(
    26→		categoryId?: number,
    27→		limit = 20,
    28→	): Promise<PromotionalProductsResponseDto> {
    29→		try {
    30→			const halfLimit = Math.floor(limit / 2);
    31→
    32→			const dbPromotionalProducts = categoryId
    33→				? await this.dbPromotionalProductsService.getProductsByCategory({
    34→						categoryId,
    35→						limit: halfLimit,
    36→					})
    37→				: await this.dbPromotionalProductsService.getRandomProducts(halfLimit);
    38→
    39→			const promotionalProducts: IRelatedProduct[] = [];
    40→
    41→			if (dbPromotionalProducts.length > 0) {
    42→				const productIds = dbPromotionalProducts.map((p) => String(p.product_id));
    43→
    44→				try {
    45→					const algoliaHits = await this.algoliaService.getMultipleObjects(productIds);
    46→
    47→					const listOfActiveProducts = await this.styleService.getStylesInStockByIds({
    48→						styleIds: productIds.map((id) => Number(id)),
    49→					});
    50→
    51→					for (const hit of algoliaHits) {
    52→						if (hit.product_id) {
    53→							const relatedProduct = this.algoliaService.mapHitToRelatedProduct(
