export const DEFAULT_RELATED_PRODUCTS_CACHE_TTL = 36 * 60 * 60 * 1000;
export const DEFAULT_CURATED_ADDONS_CACHE_TTL = 5 * 60 * 60 * 1000;

export const DEFAULT_PROCESS_STYLES_BATCH_SIZE = 100;

export const STYLES_HASHING_ALGORITHM = 'sha256';

export const DEFAULT_PRICING_ALGORITHM = 'default-2022-03-24';

export const REDIS_READ_CLIENT = 'REDIS_READ_CLIENT';
export const REDIS_WRITE_CLIENT = 'REDIS_WRITE_CLIENT';
export const CACHE_WRITE_MANAGER = 'CACHE_WRITE_MANAGER';
export const CACHE_READ_MANAGER = 'CACHE_READ_MANAGER';

export enum dailyTrackingKeys {
	MMS_REQUESTS = 'mms_requests',
	ALGOLIA_REQUESTS = 'algolia_requests',
	CACHE_REQUESTS = 'cache_requests',
	EMPTY_ALGO_RESPONSE = 'empty_algolia_response',
	RELATED_PRODUCTS_REQUESTS = 'related_products_requests',
	CURATED_ADDONS_REQUESTS = 'curated_addons_requests',
}

export const styleStatus = {
	ACTIVE: 'active',
	INACTIVE: 'inactive',
	RETIRED: 'retired',
	OFFSITE: 'offsite',
	IN_PROGRESS: 'in-progress',
	PREVIEW: 'preview',
